import React, { useState } from 'react';

export default function Controls({ onInsert, onExtract, onClear }) {
  const [key, setKey] = useState('');
  return (
    <div className="controls" style={styles.container}>
      <input 
        type="number" 
        value={key} 
        onChange={e => setKey(e.target.value)}
        placeholder="Enter key"
        style={styles.input}
      />
      <button 
        onClick={() => { 
          if (key !== '') { 
            onInsert(Number(key)); 
            setKey(''); 
          }
        }}
        style={styles.button}
      >
        Insert
      </button>
      <button onClick={onExtract} style={styles.button}>
        Extract Min
      </button>
      <button onClick={onClear} style={styles.button}>
        Clear Heap
      </button>
    </div>
  );
}

const styles = {
  container: {
    padding: '10px',
    background: '#f0f0f0',
    borderRadius: '4px',
    display: 'flex',
    gap: '10px',
    alignItems: 'center'
  },
  input: {
    padding: '8px',
    borderRadius: '4px',
    border: '1px solid #ccc'
  },
  button: {
    padding: '8px 16px',
    borderRadius: '4px',
    border: '1px solid #2196f3',
    background: '#2196f3',
    color: 'white',
    cursor: 'pointer'
  }
};
